import{_ as i,X as e,Y as r,Z as d,$ as a,a3 as t}from"./framework-abbf9d44.js";const n="/assets/cc7d1f56-08d2-4786-b0e0-ad2b023d84fd-8ba97314.png",l="/assets/版本号申请规划-流程图-05f19604.jpg",h="/assets/版本申请统计-d34c1cd7.png",s="/assets/应用-0038da0c.png",c={},o=a("h1",{id:"",tabindex:"-1"},[a("a",{class:"header-anchor",href:"#","aria-hidden":"true"},"#")],-1),p=a("p",null,"版本像是服装的款式和尺码，像是汽车的型号和生产批次，更像是一本书籍的出版号，每一个版本都有不同的内容和修订记录。通过版本我们能更了解我们的产品，能保证产品的质量与可靠性，能更好的连接用户",-1),f=t(`<h2 id="为什么做" tabindex="-1"><a class="header-anchor" href="#为什么做" aria-hidden="true">#</a> 为什么做？</h2><p>通常觉得不需要，主要是两点：</p><pre><code>- 项目不多。没有版本号，影响不大
- 人员不多。问题解决比较方便
</code></pre><p>一旦团队人数稍微上去一些，各种问题就接踵而至，代码冲突、文件丢失、版本覆盖、制品不一致等问题，让人心力憔悴。越发觉得版本的重要性</p><h2 id="意义" tabindex="-1"><a class="header-anchor" href="#意义" aria-hidden="true">#</a> 意义</h2><p>有了版本管理，之前的问题，可以减少，或者不再出现。而且版本管理带来以下几个作用：</p><ol><li>追溯: 每个版本的变化，了解软件从哪里来、经历了什么，fix也有迹可循</li><li>协作: 版本在内、外传递，保证大家工作的一致性</li><li>可控制：软件的质量和稳定性，可通过版本标记，以确保制品的稳定</li><li>统一：避免理解误差</li></ol><h2 id="如何做" tabindex="-1"><a class="header-anchor" href="#如何做" aria-hidden="true">#</a> 如何做？</h2><p>版本控制系统: 其实就是我们常用的Git、SVN等。但研发通常只用来做，团队的协同开发，并没有把版本带入进去。</p><p>分支管理: 主分支、开发分支、测试分支、发布分支等。</p><p>版本号管理: 结合CI，进行强制绑定</p><p>提交信息管理：DevOps 时，一定要做提交规范</p><h2 id="具体规划" tabindex="-1"><a class="header-anchor" href="#具体规划" aria-hidden="true">#</a> 具体规划</h2><p>在了解了版本相关的知识后，做了如下操作。</p><h3 id="明确目的" tabindex="-1"><a class="header-anchor" href="#明确目的" aria-hidden="true">#</a> 明确目的</h3><p>通过建立版本号申请流程，规避产线版本号不统一、版本号复用、不规范等问题。降低项目交付中的因为版本号引起的故障概率，提升git pipeline中流水线的效率</p><p>总结一下就是，解决以下几个问题，达到提升制品质量和交付质量的目的。</p><ol><li>版本号不统一</li><li>版本号复用</li><li>fix版本缺失</li><li>功能与版本不统一</li></ol><h3 id="制定原则" tabindex="-1"><a class="header-anchor" href="#制定原则" aria-hidden="true">#</a> 制定原则</h3><ol><li><p>自动化</p><p>降低误差，减少人员重复性操作，保证了工作的效率，避免了类似等待这种，无意义的时间消耗。</p></li><li><p>最少的改变</p><p>尽量保持目前工作习惯，尽可能不要去做一些推倒性动作，避免工作受阻。</p></li><li><p>足够简单</p><p>尽可能少的操作。过多的操作会影响整个流程效率以及工作的推进，落地困难。</p></li></ol><h3 id="确定方案" tabindex="-1"><a class="header-anchor" href="#确定方案" aria-hidden="true">#</a> 确定方案</h3><figure><img src="`+n+'" alt="版本号申请" tabindex="0" loading="lazy"><figcaption>版本号申请</figcaption></figure><figure><img src="'+l+'" alt="整体流程" tabindex="0" loading="lazy"><figcaption>整体流程</figcaption></figure><h3 id="实施推进" tabindex="-1"><a class="header-anchor" href="#实施推进" aria-hidden="true">#</a> 实施推进</h3><ol><li>研发流程</li><li>运维pipeline</li><li>开发管理平台</li></ol><h3 id="最终结果" tabindex="-1"><a class="header-anchor" href="#最终结果" aria-hidden="true">#</a> 最终结果</h3><figure><img src="'+h+'" alt="版本申请统计" tabindex="0" loading="lazy"><figcaption>版本申请统计</figcaption></figure><figure><img src="'+s+'" alt="应用统计" tabindex="0" loading="lazy"><figcaption>应用统计</figcaption></figure><h2 id="总结" tabindex="-1"><a class="header-anchor" href="#总结" aria-hidden="true">#</a> 总结</h2><p>版本管理是软件开发中的重要环节，它可以帮助团队成员协同工作、管理代码和制品的变化、提高工作效率和质量。自动化部署和测试等都高度依赖版本管理。做好版本的管理，可谓是团队步入正轨的第一步。</p>',30);function _(g,u){return e(),r("div",null,[o,p,d("more"),f])}const b=i(c,[["render",_],["__file","版本管理.html.vue"]]);export{b as default};
